var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"여인이 처음 눈을 뜬 날은 적막한 밤을 눈이 지워 내리는 겨울날이었다.","JPN":"女性が初めて目覚めたのは、寂寞たる夜を雪が消すように降る冬の日だった。","ENG":"The day the woman first opened her eyes was a winter night, where snow fell and erased all sound.","TWN":"女子第一次睜開眼睛的那天，是一個寂靜的夜晚，雪花飄落的冬日。"},"stage":{"bg":"THRONE","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이성과 고통마저 하얗게 염하여 세상을 원망하고, 삶의 자취를 지워가는 세상.","JPN":"理性と苦痛さえも白く塗りつぶされ、現実を恨み、生の痕跡が消えてゆく世界。","ENG":"A world that cursed life, bleaching away even reason and pain, erasing all trace of existence.","TWN":"連理智和痛苦都被白色染盡，怨恨著世界，抹去生活痕跡的世界。"},"stage":{"bg":"THRONE","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"그녀는 차디찬 고독이 죽음보다 두려운 것을 알고 있음에.","JPN":"冷たい孤独が死よりも恐ろしいということをわかっていた彼女は……","ENG":"She knew that bitter solitude could be more terrifying than death.","TWN":"她知道冰冷的孤獨比死亡更可怕。"},"stage":{"bg":"THRONE","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"긴 겨울이 끝나고, 언젠가 봄이 오기를 바라며 열두 개의 별을 하늘에 새겼다.","JPN":"長い冬の果てにいつか春が来ることを祈り、12の星を空に刻んだ。","ENG":"Hoping spring would come after the long winter, she carved twelve stars into the sky.","TWN":"漫長的冬天結束後，期待著有一天春天會到來，於是在天空中刻下了十二顆星星。"},"stage":{"bg":"THRONE","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"먼 훗날. 멸망을 목도한 세계의 원혼들이 길을 잃었을 때.","JPN":"遠い未来、滅びを迎えた世界の怨霊たちが道に迷った時……","ENG":"So that one day, when the children who witnessed the world's ruin lost their way...","TWN":"遙遠的未來。當目睹毀滅的世界的冤魂迷失方向時。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 새긴 마지막 별빛이, 그들을 구원의 길로 인도하길 바라며.","JPN":"彼女が刻んだ最後の星の光が、彼らを救いへと導いてくれることを願いながら。","ENG":"They might find salvation, guided by that starlight.","TWN":"願她銘刻的最後星光，引導他們走向救贖之路。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이건 말도 안 돼…….","JPN":"こ、これはあり得ん……","ENG":"Th-this can't be happening...","TWN":"這、這不可能……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그 힘을, 왜 하필 네가……?","JPN":"その力を、なぜ貴様が……？","ENG":"Why do you have that power...?","TWN":"為什麼偏偏是你擁有那股力量……？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"아니. 인도자가 남긴 별빛은 무구에 담긴 힘 따위가 아니야.","JPN":"いや。導き手が残した星の光は武具に込められた力などではない。","ENG":"No. The starlight left by the Guide was never about the power sealed inside the Armament.","TWN":"不。引導者留下的星光並不是武具中蘊含的力量之類的東西。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그 사실을 망각하고 무구를 무기로써 다룬 순간, 이미 네놈의 계획은 무너졌었다.","JPN":"その事実を忘れ、武具を武器としてしか扱わなかった時点から、すでに貴様の計画は失敗していた。","ENG":"The moment you treated the Armament as a weapon and forgot that truth... your plan was doomed to fail.","TWN":"當你忘記這一事實並將武具作為武具使用的那一刻，你的計畫已經崩潰了。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"……하. 웃기지도 않는군. 고작 전임을 따라 할 뿐인 애송이가 나를 가르치려 들다니.","JPN":"……は。ふざけたことを。たかが先代の真似をするだけの小娘が俺に説教とは。","ENG":"...Hah. Don't make me laugh. You're just a kid mimicking your predecessor, and now you think you can lecture me?","TWN":"……是。真是可笑。一個模仿前任的丫頭竟然想教訓我。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"고유무장의 힘을 얻었음에도 내 앞에 나타난 태도만큼은 인정하지.","JPN":"固有武装の力を手に入れてもなお、俺の前に現れたその態度だけは認めよう。","ENG":"Still, I'll give you this. You had the nerve to stand before me even after claiming the Unique Gear.","TWN":"即使獲得了專屬武裝的力量，但我仍然不認可你在我面前的態度。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"허나 착각하고 있는 게 있지 않나?","JPN":"だが、勘違いしていないか？","ENG":"But don't be mistaken.","TWN":"但是你是不是有什麼誤會？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈이 무구의 힘을 취했을지언정, 다시 빼앗는 건 내게 어려운 일이 아니다.","JPN":"貴様が武具の力を手に入れたとて、それをまた奪うことは俺には簡単なことだ。","ENG":"You may have taken its power, but taking it back won't be hard for me.","TWN":"即使你奪取了無垢之力，重新奪回對我來說也不是什麼難事。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그대야말로 착각하고 있군.","JPN":"貴様こそ勘違いしている。","ENG":"You're the one who's mistaken.","TWN":"你才是搞錯了。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"비록 기사단이 승패에 관계없이 명예를 위해 싸우지만…….","JPN":"騎士団は勝敗に関係なく、名誉のために戦うが……","ENG":"Even if we knights fight for honor, win or lose...","TWN":"雖然騎士團無論勝負都為榮譽而戰……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"적어도 이 전장에서, 나는 누구에게도 지지 않아.","JPN":"少なくともこの戦場で、私は誰にも負けない。","ENG":"On this battlefield, I won't lose to anyone.","TWN":"至少在這個戰場上，我不會輸給任何人。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈. 애송이들이 단장이라고 떠받들어주니 자신이 뭐라도 된다고 생각하는 거냐?","JPN":"貴様。虫けらどもに団長だと称えられ、自分が何かになったとでも思っているのか？","ENG":"Just because those kids call you \\"Captain,\\" you think you've become someone important?","TWN":"你這傢伙。小鬼們尊你為團長，就真以為自己是個人物了嗎？"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_41"},{"id":"L24_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"좋다. 그렇다면 현실이 무엇인지, 내 몸소 알려주지…!!","JPN":"いいだろう。ならば現実とは何か、俺が直接教えてやる……！！","ENG":"Fine. I'll personally teach you what the real world is like...!!","TWN":"好吧。那麼讓我親自告訴你，什麼才是現實…！！"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_C_ARROW_IN_TRAILER_42"},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"슬픔을 삼켜라.","JPN":"悲しみを飲め。","ENG":"Swallow your sorrow.","TWN":"吞下悲傷。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_63"},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"역병이 퍼진 세상의 끝에… 그들의 희생이 비로소 희망을 위한 초석이 되리라.","JPN":"疫病が広がった世界の果てに……彼らの犠牲がやがて希望の礎となるだろう。","ENG":"At the end of a world consumed by plague... their sacrifice will become the foundation of hope.","TWN":"瘟疫蔓延的世界盡頭……他們的犧牲終將成為希望的基石。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_64"},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"처녀자리의 기사, 에스테로사 드 슈발리에.","JPN":"乙女座の騎士、エステロサ・ド・シュヴァリエ。","ENG":"I, Esterosa de Chevalier, Knight of Virgo.","TWN":"處女座騎士，聖騎士艾斯特洛索。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_65"},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이곳에서 기사의 소임을 다하고자, 감히 여러분의 긍지를 받들겠습니다.","JPN":"ここで騎士の役目を果たしたく、皆さんの誇りを背負います。","ENG":"Here, I fulfill my duty as a knight and I humbly carry your pride.","TWN":"在此履行騎士的職責，敢於承載各位的榮耀。"},"stage":{"bg":"COLLOSEUM_ASH","bgm":"THEMA_SEASON2_VOCAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ZODIAC_CA_CHARLOTTE_IN_TRAILER_66"}]`);export{e as default};